<template>
  <div>
    <Navbar />
    <NuxtPage />
    <Footer />
    <CtaFloatingButton />
  </div>
</template>

<script setup lang="ts">
// Scroll reveal effect — persist one IntersectionObserver across page
// navigations instead of disconnecting/recreating. On route change we
// simply discover new .reveal elements and feed them to the same observer.
// This avoids the race where disconnecting mid-transition drops elements
// whose intersection state is in-flight.
const nuxtApp = useNuxtApp()

const observer = new IntersectionObserver(
  (entries) => {
    entries.forEach((entry) => {
      if (entry.isIntersecting) {
        entry.target.classList.add('visible')
        observer.unobserve(entry.target)
      }
    })
  },
  { threshold: 0.05, rootMargin: '0px 0px -5% 0px' }
)

function observeRevealElements() {
  const revealEls = document.querySelectorAll<HTMLElement>('.reveal, .reveal-left, .reveal-right')

  // Small delay to let the page transition finish and DOM settle.
  // requestAnimationFrame guarantees the browser has painted the new page.
  requestAnimationFrame(() => {
    revealEls.forEach((el) => {
      // Above-the-fold → reveal immediately without waiting for IntersectionObserver.
      if (el.getBoundingClientRect().top < window.innerHeight * 0.95) {
        el.classList.add('visible')
        return
      }
      // Below the fold → let the observer handle it when the user scrolls.
      observer.observe(el)
    })
  })
}

onMounted(() => {
  observeRevealElements()
})

// page:finish fires after every client-side navigation (including the initial
// SSR hydration) once the new page component has mounted and its transition
// animation has completed.  This is the correct lifecycle point — not
// watch(route.fullPath) which fires mid-transition before the DOM is ready.
nuxtApp.hook('page:finish', () => {
  observeRevealElements()
})

onBeforeUnmount(() => {
  observer.disconnect()
})
</script>
